    let valid_business_lines = ["electronics", "grocery", "pharmacy", "restaurant"];
    let mut valid_coupons = Vec::new();

    for i in 0..code.len() {
        let code = &code[i];
        let business_line = &businessLine[i];
        let is_active = isActive[i];

        // Check if code is valid
        if code.is_empty() {
            continue;
        }
        if !code.chars().all(|c| c.is_alphanumeric() || c == '_') {
            continue;
        }

        // Check if business line is valid
        if !valid_business_lines.contains(&business_line) {
            continue;
        }

        // Check if active
        if !is_active {
            continue;
        }

        // If all conditions are met, add to valid coupons
        valid_coupons.push(code.clone());
    }

    // Sort by business line order and then by code lexicographically
    valid_coupons.sort_by(|a, b| {
